const prefixes = [opts.exec, opts.interpolate, opts.raw].reduce(
  (accumulator, prefix) => {
    if (accumulator && prefix) {
      return accumulator + '|' + escapeRegExp(prefix)
    } else if (prefix) {
      // accumulator is falsy
      return escapeRegExp(prefix)
    }
    // prefix and accumulator are both falsy
    return accumulator
  },
  ''
)

